<?php
namespace App\Modules\Hr\Engagement\Actions;
use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Engagement\Models\HrSurvey; use App\Modules\Hr\Engagement\Models\HrSurveyResponse; use App\Modules\Hr\Personnel\Models\HrEmployee;
class SubmitSurveyResponseAction { public function __construct(private HrAuditService $audit){} public function execute(HrSurvey $survey,HrEmployee $employee,array $answers):HrSurveyResponse{$tenant=app(TenantContext::class)->getId();abort_unless(auth()->user()?->hasHrPermission('hr.engagement.view'),403);abort_unless($survey->legal_entity_id===$tenant&&$employee->legal_entity_id===$tenant&&$employee->user_id===auth()->id(),404);abort_unless($survey->status==='active'&&today()->betweenIncluded($survey->starts_on,$survey->ends_on),422,'Anket yanıt kabul etmiyor.');$clean=[];$enps=null;foreach($survey->questions as $q){$id=(string)$q['id'];$value=$answers[$id]??null;$required=(bool)($q['required']??true);abort_if($required&&($value===null||$value===''),422,"{$q['label']} yanıtı zorunludur.");if($value===null||$value===''){$clean[$id]=null;continue;}if($q['type']==='scale'){abort_unless(is_numeric($value)&&$value>=1&&$value<=5,422);$value=(int)$value;}elseif($q['type']==='enps'){abort_unless(is_numeric($value)&&$value>=0&&$value<=10,422);$value=(int)$value;$enps=$value;}else{$value=trim((string)$value);abort_if(mb_strlen($value)>2000,422);}$clean[$id]=$value;}$hash=hash_hmac('sha256',$survey->id.':'.$employee->id,(string)config('app.key'));abort_if(HrSurveyResponse::withoutGlobalScope('tenant')->where('survey_id',$survey->id)->where('respondent_hash',$hash)->exists(),422,'Bu anketi daha önce yanıtladınız.');$response=HrSurveyResponse::create(['legal_entity_id'=>$tenant,'survey_id'=>$survey->id,'employee_id'=>$survey->is_anonymous?null:$employee->id,'respondent_hash'=>$hash,'answers'=>$clean,'enps_score'=>$enps,'submitted_at'=>now()]);if($survey->is_anonymous)$this->audit->logAnonymousEvent('engagement_survey_response_submitted','Anonim anket yanıtı alındı.',['survey_id'=>$survey->id]);else $this->audit->log('engagement_survey_response_submitted',$survey,null,['anonymous'=>false]);return $response;} }
